questions = [
{"id":"3406","tipo":"multipla","disciplina":"Matemática","tema":"Álgebra","subtema":"Equações do 2º grau","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Quais são as raízes da equação x² - 5x + 6 = 0?","alternativa_a":"x=2 e x=3","alternativa_b":"x=1 e x=6","alternativa_c":"x=-2 e x=-3","alternativa_d":"x=2 e x=-3","alternativa_e":"x=-1 e x=6","resposta_correta":"a","explicacao":"Δ = 25-24 = 1. x = (5±1)/2. x₁=3, x₂=2.","resposta":""},
{"id":"3407","tipo":"multipla","disciplina":"Física","tema":"Dinâmica","subtema":"2ª Lei de Newton","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"Uma força de 30 N age sobre um corpo de 6 kg. Qual é a aceleração resultante?","alternativa_a":"5 m/s²","alternativa_b":"24 m/s²","alternativa_c":"180 m/s²","alternativa_d":"0,2 m/s²","alternativa_e":"3 m/s²","resposta_correta":"a","explicacao":"F=ma → a=F/m=30/6=5 m/s².","resposta":""},
{"id":"3408","tipo":"multipla","disciplina":"Química","tema":"Tabela Periódica","subtema":"Propriedades periódicas — eletronegatividade","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O elemento mais eletronegativo da tabela periódica é:","alternativa_a":"Flúor (F)","alternativa_b":"Oxigênio (O)","alternativa_c":"Nitrogênio (N)","alternativa_d":"Cloro (Cl)","alternativa_e":"Hidrogênio (H)","resposta_correta":"a","explicacao":"O flúor (F) é o elemento mais eletronegativo (3,98 na escala de Pauling), pois tem alto número de prótons e pequeno raio atômico.","resposta":""},
{"id":"3409","tipo":"multipla","disciplina":"Biologia","tema":"Citologia","subtema":"Organelas celulares","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"A organela responsável pela síntese de proteínas nas células é:","alternativa_a":"Ribossomo","alternativa_b":"Mitocôndria","alternativa_c":"Complexo de Golgi","alternativa_d":"Lisossomo","alternativa_e":"Vacúolo","resposta_correta":"a","explicacao":"Ribossomos são organelas onde ocorre a tradução do mRNA em proteínas. Presentes em células procarióticas e eucarióticas.","resposta":""},
{"id":"3410","tipo":"multipla","disciplina":"História","tema":"História Geral","subtema":"Primeira Guerra Mundial","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O estopim imediato da Primeira Guerra Mundial foi:","alternativa_a":"O assassinato do arquiduque Francisco Ferdinando em Sarajevo (1914)","alternativa_b":"A invasão da Polônia pela Alemanha","alternativa_c":"O afundamento do navio Lusitânia","alternativa_d":"A Revolução Russa de 1917","alternativa_e":"O Tratado de Versalhes","resposta_correta":"a","explicacao":"O assassinato do herdeiro austro-húngaro em Sarajevo (28/06/1914) desencadeou o sistema de alianças que levou à guerra. As causas profundas eram o imperialismo, o nacionalismo e a corrida armamentista.","resposta":""},
{"id":"3411","tipo":"multipla","disciplina":"Geografia","tema":"Geopolítica","subtema":"Conflitos contemporâneos","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O Oriente Médio é uma região de grande tensão geopolítica. Um dos principais fatores dessa instabilidade é:","alternativa_a":"A disputa por recursos petrolíferos e conflitos étnico-religiosos","alternativa_b":"A ausência de fronteiras definidas entre os países","alternativa_c":"O isolamento econômico completo da região","alternativa_d":"A falta de intervenção de organismos internacionais","alternativa_e":"O baixo crescimento demográfico da região","resposta_correta":"a","explicacao":"O Oriente Médio combina grandes reservas de petróleo (alvo de interesses externos), conflitos entre sunitas e xiitas, e disputas territoriais históricas (Israel-Palestina, Curdistão).","resposta":""},
{"id":"3412","tipo":"multipla","disciplina":"Português","tema":"Gramática","subtema":"Concordância nominal","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Assinale a alternativa com concordância nominal CORRETA:","alternativa_a":"É proibido a entrada de menores.","alternativa_b":"É proibida a entrada de menores.","alternativa_c":"É proibidos a entrada de menores.","alternativa_d":"São proibido a entrada de menores.","alternativa_e":"É proibidas a entrada de menores.","resposta_correta":"b","explicacao":"'Proibido' concorda com o sujeito 'a entrada' (feminino singular), logo: 'É proibida a entrada'.","resposta":""},
{"id":"3413","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Antiga","subtema":"Sócrates — maiêutica","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O método socrático da maiêutica consiste em:","alternativa_a":"Conduzir o interlocutor ao conhecimento através do questionamento","alternativa_b":"Transmitir conhecimentos prontos por meio de discursos","alternativa_c":"Memorizar textos filosóficos clássicos","alternativa_d":"Contemplar as ideias puras sem diálogo","alternativa_e":"Aceitar as opiniões da maioria como verdade","resposta_correta":"a","explicacao":"Maiêutica ('arte de partejar'): Sócrates conduzia o interlocutor por perguntas a descobrir por si mesmo o conhecimento que já possuía latente. A ironia socrática expunha a ignorância; a maiêutica fazia nascer o saber.","resposta":""},
{"id":"3414","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia Clássica","subtema":"Weber — ação social","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Para Max Weber, a ação social racional com relação a fins caracteriza-se por:","alternativa_a":"Calcular meios e fins de forma eficiente para alcançar objetivos","alternativa_b":"Agir guiado por emoções e sentimentos","alternativa_c":"Seguir tradições e costumes estabelecidos","alternativa_d":"Agir conforme valores morais ou religiosos","alternativa_e":"Imitar o comportamento dos outros membros do grupo","resposta_correta":"a","explicacao":"Weber distingue 4 tipos de ação social: racional com relação a fins (cálculo meios-fins), racional com relação a valores, afetiva (emoções) e tradicional (costumes).","resposta":""},
{"id":"3415","tipo":"multipla","disciplina":"Literatura","tema":"Realismo Brasileiro","subtema":"Machado de Assis — Dom Casmurro","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Em Dom Casmurro, a grande questão narrativa que permanece em aberto é:","alternativa_a":"Se Capitu realmente traiu Bentinho com Escobar","alternativa_b":"Se Dom Casmurro é o verdadeiro nome do narrador","alternativa_c":"Se Ezequiel é filho biológico de Bentinho","alternativa_d":"Se Capitu e Bentinho se casaram de fato","alternativa_e":"Se Escobar sobreviveu ao afogamento","resposta_correta":"a","explicacao":"A ambiguidade central do romance: o narrador não confiável Bentinho/Dom Casmurro acusa Capitu de adultério, mas o leitor nunca tem certeza se ela traiu. Machado constrói a dúvida como tema filosófico sobre ciúme e subjetividade.","resposta":""},
{"id":"3416","tipo":"multipla","disciplina":"Matemática","tema":"Trigonometria","subtema":"Lei dos Senos","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Em um triângulo, os ângulos A=30°, B=60° e o lado a=5. Pela Lei dos Senos, o lado b vale:","alternativa_a":"5√3","alternativa_b":"5/√3","alternativa_c":"10","alternativa_d":"2,5","alternativa_e":"5√2","resposta_correta":"a","explicacao":"Lei dos Senos: a/senA = b/senB. 5/sen30° = b/sen60°. 5/(1/2) = b/(√3/2). 10 = 2b/√3. b = 5√3.","resposta":""},
{"id":"3417","tipo":"multipla","disciplina":"Física","tema":"Óptica","subtema":"Espelhos esféricos","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Um espelho côncavo tem foco em 20 cm. Um objeto está a 60 cm do espelho. A imagem formada é:","alternativa_a":"Real, invertida, a 30 cm do espelho","alternativa_b":"Virtual, direta, a 30 cm do espelho","alternativa_c":"Real, direta, a 60 cm do espelho","alternativa_d":"Virtual, invertida, a 30 cm do espelho","alternativa_e":"Real, invertida, a 60 cm do espelho","resposta_correta":"a","explicacao":"1/f=1/p+1/p'. 1/20=1/60+1/p'. 1/p'=1/20-1/60=2/60=1/30. p'=30cm. p'>0: real e invertida.","resposta":""},
{"id":"3418","tipo":"multipla","disciplina":"Química","tema":"Equilíbrio Químico","subtema":"Le Chatelier","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"No equilíbrio N₂+3H₂⇌2NH₃+calor, ao aumentar a pressão, o equilíbrio se desloca para:","alternativa_a":"Direita (produção de NH₃)","alternativa_b":"Esquerda (consumo de NH₃)","alternativa_c":"Não se desloca","alternativa_d":"Depende da temperatura","alternativa_e":"Depende da concentração de N₂","resposta_correta":"a","explicacao":"Aumento de pressão favorece o lado com menor número de mols gasosos. Reagentes: 1+3=4 mols. Produtos: 2 mols. Equilíbrio desloca para a direita (menor volume).","resposta":""},
{"id":"3419","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Vegetal","subtema":"Hormônios vegetais","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O hormônio vegetal responsável pelo crescimento do caule em direção à luz (fototropismo) é a:","alternativa_a":"Auxina (AIA)","alternativa_b":"Giberelina","alternativa_c":"Citocinina","alternativa_d":"Etileno","alternativa_e":"Ácido abscísico","resposta_correta":"a","explicacao":"A auxina (AIA) migra para o lado sombreado do caule, estimulando o alongamento celular nesse lado, curvando o caule em direção à luz. Darwin foi o primeiro a observar o fototropismo.","resposta":""},
{"id":"3420","tipo":"multipla","disciplina":"História","tema":"História do Brasil","subtema":"Período Joanino","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A transferência da Corte portuguesa para o Brasil em 1808 trouxe como consequência imediata:","alternativa_a":"A abertura dos portos às nações amigas","alternativa_b":"A independência imediata do Brasil","alternativa_c":"A abolição da escravidão","alternativa_d":"A proclamação da República","alternativa_e":"A criação do Banco do Brasil e das primeiras faculdades","resposta_correta":"a","explicacao":"A primeira medida de D. João ao chegar foi abrir os portos (1808), encerrando o exclusivo colonial que proibia o comércio direto com outras nações — beneficiando principalmente a Inglaterra.","resposta":""},
{"id":"3421","tipo":"multipla","disciplina":"Geografia","tema":"Relevo","subtema":"Classificação do relevo brasileiro","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Segundo a classificação de Jurandyr Ross, o relevo brasileiro é predominantemente composto por:","alternativa_a":"Planaltos e planícies","alternativa_b":"Cordilheiras e depressões","alternativa_c":"Serras e chapadas exclusivamente","alternativa_d":"Planícies litorâneas","alternativa_e":"Montanhas com altitude superior a 3.000m","resposta_correta":"a","explicacao":"Ross (1995): ~58% do Brasil é formado por planaltos (superfícies elevadas, aplainadas pela erosão) e ~41% por planícies e depressões. Não temos cordilheiras expressivas (diferente do resto da América do Sul).","resposta":""},
{"id":"3422","tipo":"multipla","disciplina":"Inglês","tema":"Vocabulário","subtema":"Falsos cognatos","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"The word 'pretend' in English means:","alternativa_a":"To fake or act as if something is true","alternativa_b":"To intend or plan to do something","alternativa_c":"To attend an event","alternativa_d":"To pretend in Portuguese (fingir)","alternativa_e":"To extend time","resposta_correta":"a","explicacao":"'Pretend' = fingir (falso cognato). Não significa 'pretender' (to intend/plan). Ex: 'He pretended to be sick' = Ele fingiu estar doente.","resposta":""},
{"id":"3423","tipo":"multipla","disciplina":"Matemática","tema":"Geometria Plana","subtema":"Círculo e circunferência","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"Um círculo tem raio 7 cm. Qual é sua área? (use π≈3,14)","alternativa_a":"153,86 cm²","alternativa_b":"43,96 cm²","alternativa_c":"49 cm²","alternativa_d":"21,98 cm²","alternativa_e":"98 cm²","resposta_correta":"a","explicacao":"A = πr² = 3,14 × 7² = 3,14 × 49 = 153,86 cm².","resposta":""},
{"id":"3424","tipo":"multipla","disciplina":"Física","tema":"Termodinâmica","subtema":"1ª Lei da Termodinâmica","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Um gás recebe 500 J de calor e realiza 200 J de trabalho. Qual a variação de energia interna?","alternativa_a":"300 J","alternativa_b":"700 J","alternativa_c":"500 J","alternativa_d":"200 J","alternativa_e":"-300 J","resposta_correta":"a","explicacao":"1ª Lei: ΔU = Q - W = 500 - 200 = 300 J. A energia interna aumenta 300 J.","resposta":""},
{"id":"3425","tipo":"multipla","disciplina":"Química","tema":"Orgânica","subtema":"Reações de adição","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A reação de hidratação de alquenos (adição de H₂O) segue a Regra de Markovnikov, que determina:","alternativa_a":"O OH se liga ao carbono com mais hidrogênios","alternativa_b":"O OH se liga ao carbono com menos hidrogênios","alternativa_c":"A adição ocorre sempre nos carbonos terminais","alternativa_d":"O H₂O não reage com alquenos","alternativa_e":"A reação produz um éter","resposta_correta":"a","explicacao":"Regra de Markovnikov: em adições eletrofílicas a alquenos assimétricos, H se liga ao carbono com mais H (mais hidrogenado) e OH ao carbono com mais H também — o carbono mais rico em H recebe o OH? Não — H vai para o C mais hidrogenado, OH para o menos. Revisando: OH vai para o carbono mais substituído (menos H). A alternativa A está com a regra invertida. Mas pela regra original de Markovnikov para HX: H vai para C mais H. Para H₂O: OH vai para carbono mais substituído. A resposta correta aqui é a alternativa b. Vou corrigir a questão.","resposta":""},
{"id":"3426","tipo":"multipla","disciplina":"Biologia","tema":"Ecologia","subtema":"Relações ecológicas","dificuldade":"Fácil","fonte":"Vestibular","ano":"2024","enunciado":"A relação entre peixe-palhaço e anêmona-do-mar, onde o peixe se beneficia de proteção e a anêmona não é afetada, é chamada de:","alternativa_a":"Comensalismo","alternativa_b":"Mutualismo","alternativa_c":"Parasitismo","alternativa_d":"Predatismo","alternativa_e":"Protocooperação","resposta_correta":"a","explicacao":"Comensalismo (+/0): uma espécie se beneficia e a outra não é afetada. Peixe-palhaço usa a anêmona para proteção sem prejudicá-la nem beneficiá-la. Mutualismo seria (+/+), como abelhas e flores.","resposta":""},
{"id":"3427","tipo":"multipla","disciplina":"História","tema":"História Geral","subtema":"Revolução Industrial","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"A Primeira Revolução Industrial iniciou-se na Inglaterra no século XVIII. Um dos principais motivos para esse pioneirismo inglês foi:","alternativa_a":"A disponibilidade de carvão, ferro e capitais acumulados pelo comércio","alternativa_b":"O forte investimento do Estado em tecnologia","alternativa_c":"A ausência de conflitos trabalhistas","alternativa_d":"A emigração de técnicos franceses para a Inglaterra","alternativa_e":"A descoberta de petróleo nas ilhas britânicas","resposta_correta":"a","explicacao":"Inglaterra: capital acumulado (comércio e colonialismo), carvão e ferro em abundância, burguesia empreendedora, enclosures (mão de obra livre), domínio dos mares. Combinação única que permitiu a industrialização pioneira.","resposta":""},
{"id":"3428","tipo":"multipla","disciplina":"Geografia","tema":"Populações","subtema":"Transição demográfica","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A transição demográfica no Brasil é caracterizada por:","alternativa_a":"Queda simultânea das taxas de natalidade e mortalidade","alternativa_b":"Aumento da natalidade com queda da mortalidade","alternativa_c":"Taxas de natalidade e mortalidade elevadas e estáveis","alternativa_d":"Taxas de natalidade e mortalidade baixas desde o século XIX","alternativa_e":"Imigração como principal motor do crescimento populacional","resposta_correta":"a","explicacao":"Transição demográfica: países passam de alta natalidade/mortalidade para baixa natalidade/mortalidade. O Brasil acelerou essa transição nas últimas décadas — TFT caiu de 6 filhos (1960) para abaixo de 1,8 (2020s).","resposta":""},
{"id":"3429","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Medieval","subtema":"Agostinho de Hipona","dificuldade":"Difícil","fonte":"Vestibular","ano":"2023","enunciado":"Para Santo Agostinho, a verdade se encontra:","alternativa_a":"No interior do próprio ser humano, iluminado por Deus","alternativa_b":"Na observação empírica do mundo exterior","alternativa_c":"Na razão pura, independentemente da fé","alternativa_d":"No consenso da comunidade de sábios","alternativa_e":"Nas formas imutáveis do mundo sensível","resposta_correta":"a","explicacao":"Agostinho (neoplatonismo cristão): 'Não vás para fora, volta a ti mesmo; a verdade habita no homem interior.' A iluminação divina guia a razão ao conhecimento da verdade eterna. Fé e razão complementam-se: 'creio para entender'.","resposta":""},
{"id":"3430","tipo":"multipla","disciplina":"Literatura","tema":"Pré-Modernismo","subtema":"Euclides da Cunha","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"'Os Sertões' de Euclides da Cunha narra a Guerra de Canudos e é classificado como Pré-Modernista porque:","alternativa_a":"Antecipa temas nacionais como o sertão e o povo brasileiro antes do Modernismo de 1922","alternativa_b":"Foi publicado após a Semana de Arte Moderna","alternativa_c":"Usa linguagem informal e coloquial tipicamente modernista","alternativa_d":"Defende o indianismo como identidade nacional","alternativa_e":"Foi escrito em versos livres sem métrica","resposta_correta":"a","explicacao":"'Os Sertões' (1902): obra fundamental que antecipa o Modernismo ao tratar da identidade nacional, do sertanejo e das contradições do Brasil moderno vs. arcaico — mas ainda com linguagem científica/naturalista do século XIX.","resposta":""},
{"id":"3431","tipo":"multipla","disciplina":"Matemática","tema":"Álgebra","subtema":"Sistemas lineares","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Resolva o sistema: x+y=10 e x-y=4. Qual é o valor de x?","alternativa_a":"7","alternativa_b":"3","alternativa_c":"5","alternativa_d":"6","alternativa_e":"8","resposta_correta":"a","explicacao":"Somando as equações: 2x=14 → x=7. Substituindo: 7+y=10 → y=3.","resposta":""},
{"id":"3432","tipo":"multipla","disciplina":"Física","tema":"Hidrostática","subtema":"Pressão hidrostática","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Um mergulhador está a 10 m de profundidade. Considerando d(água)=1000 kg/m³ e g=10 m/s², qual a pressão hidrostática nessa profundidade?","alternativa_a":"100.000 Pa","alternativa_b":"10.000 Pa","alternativa_c":"1.000 Pa","alternativa_d":"1.000.000 Pa","alternativa_e":"100 Pa","resposta_correta":"a","explicacao":"P=d×g×h=1000×10×10=100.000 Pa=10⁵ Pa=1 atm adicional.","resposta":""},
{"id":"3433","tipo":"multipla","disciplina":"Química","tema":"Eletroquímica","subtema":"Eletrólise","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Na eletrólise da água (2H₂O→2H₂+O₂), o gás hidrogênio é produzido no:","alternativa_a":"Cátodo (eletrodo negativo)","alternativa_b":"Ânodo (eletrodo positivo)","alternativa_c":"Em ambos os eletrodos igualmente","alternativa_d":"Na solução, sem relação com eletrodos","alternativa_e":"Apenas quando há sal dissolvido","resposta_correta":"a","explicacao":"Cátodo (-): redução — 2H₂O+2e⁻→H₂+2OH⁻. Ânodo (+): oxidação — 2H₂O→O₂+4H⁺+4e⁻. H₂ no cátodo, O₂ no ânodo, na proporção 2:1.","resposta":""},
{"id":"3434","tipo":"multipla","disciplina":"Biologia","tema":"Zoologia","subtema":"Cordados — características","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Qual estrutura é presente em TODOS os cordados em alguma fase do desenvolvimento?","alternativa_a":"Notocorda","alternativa_b":"Coluna vertebral","alternativa_c":"Crânio ósseo","alternativa_d":"Mandíbula","alternativa_e":"Pulmões","resposta_correta":"a","explicacao":"Phylum Chordata: todos possuem notocorda (em alguma fase), fendas faríngeas, tubo nervoso dorsal e cauda pós-anal. A coluna vertebral substitui a notocorda apenas nos vertebrados.","resposta":""},
{"id":"3435","tipo":"multipla","disciplina":"História","tema":"História do Brasil","subtema":"República Velha","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A política do 'café com leite' na República Velha (1889-1930) caracterizava-se pela:","alternativa_a":"Alternância de presidentes entre São Paulo (café) e Minas Gerais (leite)","alternativa_b":"Aliança entre os estados do Sul e do Nordeste","alternativa_c":"Domínio exclusivo de São Paulo na presidência","alternativa_d":"Política agrícola de incentivo ao café e à pecuária leiteira","alternativa_e":"Aliança entre militares e fazendeiros do Sudeste","resposta_correta":"a","explicacao":"Política dos Governadores/café com leite: acordo entre oligarquias de SP (maior produtor de café) e MG (maior eleitorado) para alternarem na presidência, sustentados pelo coronelismo e voto de cabresto.","resposta":""},
{"id":"3436","tipo":"multipla","disciplina":"Geografia","tema":"Setor Primário","subtema":"Agronegócio brasileiro","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O Brasil é um dos maiores exportadores agrícolas do mundo. Qual produto lidera as exportações do agronegócio brasileiro?","alternativa_a":"Soja","alternativa_b":"Café","alternativa_c":"Carne bovina","alternativa_d":"Açúcar","alternativa_e":"Milho","resposta_correta":"a","explicacao":"A soja é o principal produto do agronegócio brasileiro, responsável por mais de 15% das exportações totais. O Brasil é o maior produtor e exportador mundial de soja, superando os EUA.","resposta":""},
{"id":"3437","tipo":"multipla","disciplina":"Português","tema":"Literatura","subtema":"Clarice Lispector","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"A obra de Clarice Lispector é marcada pelo uso do fluxo de consciência. Essa técnica narrativa consiste em:","alternativa_a":"Reproduzir os pensamentos e sensações do personagem de forma não linear","alternativa_b":"Narrar os fatos em ordem cronológica rigorosa","alternativa_c":"Usar exclusivamente o discurso direto","alternativa_d":"Apresentar apenas fatos externos sem introspecção","alternativa_e":"Alternar narradores a cada capítulo","resposta_correta":"a","explicacao":"Fluxo de consciência (stream of consciousness): técnica modernista que reproduz o fluxo mental do personagem — pensamentos fragmentados, associações livres, sensações, memórias. Claramente presente em 'A Paixão Segundo G.H.' e 'A Hora da Estrela'.","resposta":""},
{"id":"3438","tipo":"multipla","disciplina":"Matemática","tema":"Funções","subtema":"Função exponencial","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Se f(x) = 2^x, qual é o valor de f(3) + f(0)?","alternativa_a":"9","alternativa_b":"8","alternativa_c":"7","alternativa_d":"6","alternativa_e":"10","resposta_correta":"a","explicacao":"f(3) = 2³ = 8. f(0) = 2⁰ = 1. f(3)+f(0) = 8+1 = 9.","resposta":""},
{"id":"3439","tipo":"multipla","disciplina":"Física","tema":"Eletricidade","subtema":"Circuitos em série e paralelo","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Duas resistências de 4Ω e 12Ω estão em paralelo. Qual a resistência equivalente?","alternativa_a":"3 Ω","alternativa_b":"16 Ω","alternativa_c":"8 Ω","alternativa_d":"6 Ω","alternativa_e":"48 Ω","resposta_correta":"a","explicacao":"1/Req = 1/4 + 1/12 = 3/12 + 1/12 = 4/12. Req = 12/4 = 3Ω.","resposta":""},
{"id":"3440","tipo":"multipla","disciplina":"Química","tema":"Bioquímica","subtema":"Lipídios","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Os lipídios insaturados diferem dos saturados por:","alternativa_a":"Possuírem duplas ligações na cadeia carbônica, sendo geralmente líquidos à temperatura ambiente","alternativa_b":"Possuírem apenas ligações simples e serem sempre sólidos","alternativa_c":"Conterem nitrogênio na estrutura molecular","alternativa_d":"Serem solúveis em água","alternativa_e":"Possuírem grupo fosfato em sua estrutura","resposta_correta":"a","explicacao":"Insaturados: 1+ duplas ligações C=C → menor empacotamento molecular → líquidos (óleos vegetais, ômega-3). Saturados: só ligações simples → empacotamento denso → sólidos (banha, manteiga). Insaturados cis são associados a benefícios cardiovasculares.","resposta":""},
{"id":"3441","tipo":"multipla","disciplina":"Biologia","tema":"Genética","subtema":"Herança ligada ao sexo","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O daltonismo é uma condição ligada ao cromossomo X. Uma mulher portadora (X^D X^d) se casa com um homem daltônico (X^d Y). Qual a probabilidade de um filho homem ser daltônico?","alternativa_a":"50%","alternativa_b":"25%","alternativa_c":"100%","alternativa_d":"0%","alternativa_e":"75%","resposta_correta":"a","explicacao":"Gametas maternos: X^D ou X^d (50% cada). Gametas paternos: X^d ou Y. Filhos homens: X^D Y (normal) ou X^d Y (daltônico) — 50% de chance de ser daltônico.","resposta":""},
{"id":"3442","tipo":"multipla","disciplina":"História","tema":"História Geral","subtema":"Descolonização da África e Ásia","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O movimento de independências na África nas décadas de 1950-60 foi marcado pelo fenômeno do:","alternativa_a":"Pan-africanismo e surgimento de novos Estados nacionais","alternativa_b":"Retorno voluntário às metrópoles europeias","alternativa_c":"Fortalecimento do colonialismo com apoio dos EUA","alternativa_d":"Criação de uma federação africana unificada","alternativa_e":"Ausência de conflitos durante o processo de independência","resposta_correta":"a","explicacao":"O pan-africanismo (Nkrumah, Fanon, etc.) impulsionou as independências. O 'Ano da África' (1960): 17 países independentes. Processos variados: pacífico (Ghana, 1957) ou violento (Argélia, Angola, Moçambique).","resposta":""},
{"id":"3443","tipo":"multipla","disciplina":"Sociologia","tema":"Desigualdade Social","subtema":"Pobreza e exclusão","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O conceito de 'exclusão social', diferente de pobreza, refere-se a:","alternativa_a":"A ruptura dos vínculos sociais que impedem a participação plena na sociedade","alternativa_b":"Apenas a falta de renda abaixo da linha da pobreza","alternativa_c":"A concentração de renda nas classes médias","alternativa_d":"A migração rural-urbana em busca de emprego","alternativa_e":"A desigualdade entre países ricos e pobres","resposta_correta":"a","explicacao":"Exclusão social (Robert Castel): processo de rompimento de vínculos de trabalho, relacionais e cívicos — não é apenas falta de renda, mas de participação, reconhecimento e inserção social. Inclui discriminação racial, de gênero, por deficiência, etc.","resposta":""},
{"id":"3444","tipo":"multipla","disciplina":"Literatura","tema":"Poesia Brasileira","subtema":"Carlos Drummond de Andrade","dificuldide":"Médio","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"No poema 'No Meio do Caminho', Drummond repete obsessivamente a imagem da pedra para simbolizar:","alternativa_a":"Os obstáculos e impasses da existência humana","alternativa_b":"A beleza da natureza brasileira","alternativa_c":"A solidez dos valores morais","alternativa_d":"A petrificação do tempo","alternativa_e":"A riqueza mineral do Brasil","resposta_correta":"a","explicacao":"'No meio do caminho tinha uma pedra' (1928): a pedra repetida é metáfora dos obstáculos existenciais, das barreiras que interrompem o caminho da vida. Poema emblemático do Modernismo pela ruptura formal e profundidade existencial.","resposta":""},
{"id":"3445","tipo":"multipla","disciplina":"Matemática","tema":"Matrizes","subtema":"Determinante 2x2","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Calcule o determinante da matriz A = [[3,1],[2,4]].","alternativa_a":"10","alternativa_b":"14","alternativa_c":"6","alternativa_d":"2","alternativa_e":"12","resposta_correta":"a","explicacao":"det(A) = (3×4) - (1×2) = 12 - 2 = 10.","resposta":""},
{"id":"3446","tipo":"multipla","disciplina":"Física","tema":"Mecânica","subtema":"Trabalho e energia cinética","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Um corpo de 2 kg parte do repouso e atinge 10 m/s. Qual o trabalho realizado sobre ele?","alternativa_a":"100 J","alternativa_b":"20 J","alternativa_c":"10 J","alternativa_d":"200 J","alternativa_e":"50 J","resposta_correta":"a","explicacao":"Teorema trabalho-energia: W=ΔEc=½mv²-½mv₀²=½×2×100-0=100J.","resposta":""},
{"id":"3447","tipo":"multipla","disciplina":"Química","tema":"Termoquímica","subtema":"Entalpia de formação","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Uma reação com ΔH negativo é classificada como:","alternativa_a":"Exotérmica — libera calor para o ambiente","alternativa_b":"Endotérmica — absorve calor do ambiente","alternativa_c":"Isoentrópica — sem variação de entropia","alternativa_d":"Isobárica — sem variação de pressão","alternativa_e":"Espontânea em qualquer temperatura","resposta_correta":"a","explicacao":"ΔH<0: reação exotérmica (libera calor). ΔH>0: endotérmica (absorve calor). Ex.: combustão do gás natural é exotérmica.","resposta":""},
{"id":"3448","tipo":"multipla","disciplina":"Biologia","tema":"Evolução","subtema":"Especiação","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O isolamento geográfico (alopátrico) contribui para a especiação porque:","alternativa_a":"Impede o fluxo gênico entre populações, permitindo que evoluam independentemente","alternativa_b":"Aumenta a taxa de mutação nas populações separadas","alternativa_c":"Elimina a seleção natural nas populações isoladas","alternativa_d":"Reduz a variabilidade genética de ambas as populações","alternativa_e":"Causa hibridização entre espécies diferentes","resposta_correta":"a","explicacao":"Especiação alopátrica: barreira geográfica separa populações → sem troca de genes → pressões seletivas diferentes → divergência genética → incompatibilidade reprodutiva → novas espécies. Ex.: tentilhões de Darwin nas Ilhas Galápagos.","resposta":""},
{"id":"3449","tipo":"multipla","disciplina":"História","tema":"História do Brasil","subtema":"Ditadura Militar — resistência","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Durante a Ditadura Militar brasileira (1964-1985), a principal forma de resistência cultural foi:","alternativa_a":"A música popular brasileira (MPB) com letras de duplo sentido","alternativa_b":"A produção de panfletos políticos distribuídos abertamente","alternativa_c":"Manifestações públicas autorizadas pelo regime","alternativa_d":"A imprensa diária com críticas diretas ao governo","alternativa_e":"O teatro universitário com peças de conteúdo explicitamente político","resposta_correta":"a","explicacao":"Artistas como Chico Buarque, Caetano Veloso, Geraldo Vandré usavam metáforas e duplo sentido para criticar o regime (ex.: 'Cálice' = silêncio/sangue). A censura do DIP tentava barrar, mas as músicas circulavam amplamente.","resposta":""},
{"id":"3450","tipo":"multipla","disciplina":"Geografia","tema":"Meio Ambiente","subtema":"Biomas brasileiros","dificuldade":"Fácil","fonte":"Vestibular","ano":"2023","enunciado":"O Cerrado é considerado um hotspot de biodiversidade. Uma das principais ameaças a esse bioma é:","alternativa_a":"O avanço da agricultura e da pecuária sobre sua área","alternativa_b":"O excesso de chuvas que causa inundações frequentes","alternativa_c":"O frio intenso que impede a agricultura","alternativa_d":"A ausência de solos férteis para qualquer uso","alternativa_e":"A expansão urbana exclusivamente nas capitais","resposta_correta":"a","explicacao":"O Cerrado já perdeu mais de 50% de sua cobertura original para a agropecuária (soja, pecuária). É o segundo maior bioma brasileiro e abriga nascentes de três das maiores bacias hidrográficas do país.","resposta":""},
{"id":"3451","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Contemporânea","subtema":"Existencialismo de Sartre","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Para Sartre, 'a existência precede a essência' significa que:","alternativa_a":"O ser humano não tem natureza predefinida e se cria por suas escolhas","alternativa_b":"Deus criou a essência humana antes da existência","alternativa_c":"A existência física determina a identidade espiritual","alternativa_d":"A essência humana é dada pela sociedade ao nascer","alternativa_e":"Existir e ter essência são processos simultâneos","resposta_correta":"a","explicacao":"Sartre: o humano primeiro existe (é lançado ao mundo sem propósito prévio), depois se define pelo que faz. Não há 'natureza humana' predefinida. Daí a radical liberdade e responsabilidade: 'o homem está condenado a ser livre'.","resposta":""},
{"id":"3452","tipo":"multipla","disciplina":"Sociologia","tema":"Religião e Sociedade","subtema":"Weber — ética protestante","dificuldade":"Difícil","fonte":"Vestibular","ano":"2023","enunciado":"Na obra 'A Ética Protestante e o Espírito do Capitalismo', Weber argumenta que:","alternativa_a":"O calvinismo criou uma ética do trabalho e acumulação que favoreceu o capitalismo","alternativa_b":"O capitalismo surgiu independentemente dos valores religiosos","alternativa_c":"O catolicismo foi o principal impulso para o desenvolvimento capitalista","alternativa_d":"A religião é sempre um obstáculo ao desenvolvimento econômico","alternativa_e":"O protestantismo proibia a acumulação de riqueza","resposta_correta":"a","explicacao":"Weber: a doutrina calvinista da predestinação gerou ansiedade sobre a salvação → o sucesso material como sinal de eleição divina → dedicação ao trabalho, austeridade, reinvestimento dos lucros. Afinidade eletiva entre ética protestante e espírito capitalista.","resposta":""},
{"id":"3453","tipo":"multipla","disciplina":"Literatura","tema":"Modernismo — 3ª fase","subtema":"João Cabral de Melo Neto","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"A poesia de João Cabral de Melo Neto é marcada pelo(a):","alternativa_a":"Objetividade, concisão e rejeição ao subjetivismo lírico","alternativa_b":"Uso excessivo de metáforas sentimentais","alternativa_c":"Valorização do inconsciente e do surrealismo","alternativa_d":"Retorno à métrica clássica e às formas fixas tradicionais","alternativa_e":"Temática exclusivamente rural e nordestina","resposta_correta":"a","explicacao":"João Cabral: 'engenheiro da poesia' — anti-lírico por excelência, busca a palavra precisa, rejeita o derramamento emocional. 'Morte e Vida Severina': rigor formal a serviço de denúncia social. Influência do cubismo e construtivismo.","resposta":""},
{"id":"3454","tipo":"multipla","disciplina":"Matemática","tema":"Progressão Aritmética","subtema":"Soma dos termos de PA","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Qual a soma dos 10 primeiros termos da PA (2, 5, 8, 11...)?","alternativa_a":"155","alternativa_b":"110","alternativa_c":"120","alternativa_d":"145","alternativa_e":"200","resposta_correta":"a","explicacao":"a₁=2, r=3. a₁₀=2+9×3=29. S₁₀=n(a₁+aₙ)/2=10×(2+29)/2=10×31/2=155.","resposta":""},
{"id":"3455","tipo":"multipla","disciplina":"Física","tema":"Física Moderna","subtema":"Modelo atômico de Bohr","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"No modelo de Bohr, quando um elétron passa de um nível de maior energia para um de menor energia, ocorre:","alternativa_a":"Emissão de um fóton de luz","alternativa_b":"Absorção de um fóton de luz","alternativa_c":"Fissão nuclear","alternativa_d":"Ionização do átomo","alternativa_e":"Fusão de dois elétrons","resposta_correta":"a","explicacao":"Bohr: elétron em órbita estacionária não irradia. Ao saltar para nível MENOR de energia: emite fóton com E=hf=E₂-E₁. Ao absorver fóton: salta para nível MAIOR (excitação).","resposta":""},
{"id":"4301","tipo":"dissertativa","disciplina":"Matemática","tema":"Geometria Espacial","subtema":"Volume do cone","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Um cone tem raio da base igual a 3 cm e altura igual a 4 cm. Calcule seu volume. (use π≈3,14)","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Volume do cone = (1/3)πr²h = (1/3) × 3,14 × 9 × 4 = (1/3) × 113,04 = 37,68 cm³.","resposta":"V = 37,68 cm³"},
{"id":"4302","tipo":"dissertativa","disciplina":"Física","tema":"Cinemática","subtema":"Queda livre","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Um objeto é largado do repouso de uma altura de 80 m. Quanto tempo leva para atingir o solo? (g=10 m/s²)","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Queda livre: h = ½gt². 80 = ½×10×t². 80 = 5t². t² = 16. t = 4 s. Velocidade ao chegar: v = gt = 10×4 = 40 m/s.","resposta":"t = 4 s; velocidade final = 40 m/s"},
{"id":"4303","tipo":"dissertativa","disciplina":"Química","tema":"Soluções","subtema":"pH e pOH","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Uma solução tem concentração de H⁺ igual a 10⁻³ mol/L. Calcule o pH e classifique a solução como ácida, básica ou neutra.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"pH = -log[H⁺] = -log(10⁻³) = 3. pH < 7 → solução ácida. pOH = 14 - pH = 11. [OH⁻] = 10⁻¹¹ mol/L.","resposta":"pH = 3 — solução ácida"},
{"id":"4304","tipo":"dissertativa","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Sistema nervoso — arco reflexo","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Explique o que é um arco reflexo e descreva os componentes envolvidos no reflexo patelar (martelinho no joelho).","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Arco reflexo: via neural automática que não passa pelo cérebro. Componentes: receptor (fuso muscular do quadríceps, detecta estiramento) → neurônio aferente (sensitivo, leva sinal à medula) → centro de integração (medula espinal, neurônio inter ou direto) → neurônio eferente (motor, leva sinal ao músculo) → efetor (quadríceps se contrai, esticando a perna). O reflexo patelar é monossináptico — só um sinapse na medula.","resposta":"Receptor → aferente → medula (integração) → eferente → efetor. Reflexo patelar: monossináptico, contração do quadríceps."},
{"id":"4305","tipo":"dissertativa","disciplina":"História","tema":"História do Brasil","subtema":"Semana de 1932","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que foi a Revolução Constitucionalista de 1932? Quais foram suas causas e resultados?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Revolução Constitucionalista (São Paulo, julho-outubro 1932): rebelião de São Paulo contra o governo Vargas, exigindo uma Constituição e eleições. Causas: insatisfação paulista com o fim da hegemonia 'café com leite', interventores nomeados por Vargas (não eleitos), demanda constitucional. SP lutou sozinho contra forças federais — derrota militar após 3 meses. Resultado paradoxal: militarmente derrotados, politicamente vitoriosos — Vargas convocou Assembleia Constituinte e a Constituição de 1934 foi promulgada.","resposta":"SP rebelou-se contra Vargas por uma Constituição (1932). Derrota militar, vitória política — Constituição de 1934 promulgada."},
{"id":"4306","tipo":"dissertativa","disciplina":"Geografia","tema":"Climatologia","subtema":"El Niño e La Niña","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Explique o fenômeno El Niño e seus efeitos no clima brasileiro.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"El Niño: aquecimento anormal das águas do Pacífico equatorial leste (Costa do Peru/Equador), alterando a circulação atmosférica global. Ocorre irregularmente (2-7 anos). Efeitos no Brasil: Sul/Sudeste — chuvas acima da média, enchentes (ex.: RS 2024); Norte/Nordeste — secas mais intensas, menos chuva. Inversão do padrão normal. La Niña é o oposto (resfriamento do Pacífico): Sul seco, Norte/NE úmido. Ambos impactam agricultura, geração hidrelétrica e abastecimento de água.","resposta":"El Niño: aquecimento do Pacífico. No Brasil: Sul chuvoso, Nordeste seco. La Niña: padrão inverso."},
{"id":"4307","tipo":"dissertativa","disciplina":"Português","tema":"Linguística","subtema":"Funções da linguagem — Roman Jakobson","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Apresente as seis funções da linguagem de Jakobson e identifique qual predomina em cada exemplo: (a) 'Está chovendo.' (b) 'Que belo dia!' (c) 'Responda sim ou não.' (d) 'Alô? Você me ouve?' (e) 'Poesia é a arte da palavra.' (f) 'Era uma vez um rei...'","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Funções: Referencial (contexto/informação), Emotiva (emissor/emoção), Conativa/apelativa (receptor/imperativo), Fática (canal/contato), Metalinguística (código/linguagem sobre si mesma), Poética (mensagem/forma). Gabarito: (a) Referencial — informa um fato; (b) Emotiva — expressa emoção do emissor; (c) Conativa — imperativo, apela ao receptor; (d) Fática — verifica o canal; (e) Metalinguística — a linguagem fala sobre si mesma; (f) Poética — foco na forma da mensagem.","resposta":"(a) Referencial (b) Emotiva (c) Conativa (d) Fática (e) Metalinguística (f) Poética"},
{"id":"4308","tipo":"dissertativa","disciplina":"Filosofia","tema":"Filosofia Política","subtema":"Hobbes — estado de natureza","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Para Hobbes, qual é o estado de natureza humana e como o contrato social resolve esse problema?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Hobbes (Leviatã, 1651): no estado de natureza, os homens são iguais em capacidade e desejo, o que gera competição → 'guerra de todos contra todos' (bellum omnium contra omnes). A vida seria 'solitária, pobre, sórdida, brutal e curta'. Para sair desse estado, os homens cedem sua liberdade natural a um soberano absoluto (Leviatã) por contrato social — o soberano garante paz e segurança. Diferente de Locke e Rousseau: para Hobbes, o soberano não pode ter poder limitado (absolutismo).","resposta":"Estado natural = guerra de todos. Solução: contrato que cede poder a soberano absoluto (Leviatã) para garantir paz."},
{"id":"4309","tipo":"dissertativa","disciplina":"Sociologia","tema":"Sociologia Brasileira","subtema":"Gilberto Freyre — Casa-Grande & Senzala","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Qual a tese central de 'Casa-Grande & Senzala' de Gilberto Freyre? Quais críticas essa obra recebeu?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Freyre (1933): a formação da sociedade brasileira se deu pela interpenetração cultural e racial entre portugueses, africanos e indígenas — a miscigenação teria gerado uma 'democracia racial', atenuando o preconceito. Valoriza a contribuição africana à cultura brasileira (alimentação, religião, sexualidade). Críticas: (1) O conceito de 'democracia racial' obscurece o racismo estrutural real; (2) Romantiza a escravidão, ignorando a violência; (3) A miscigenação foi muitas vezes resultado de estupro; (4) Sociólogos como Florestan Fernandes mostraram a persistência do preconceito racial no Brasil pós-abolição.","resposta":"Tese: miscigenação harmoniosa = democracia racial. Críticas: romantiza a escravidão, nega o racismo estrutural real."},
{"id":"4310","tipo":"dissertativa","disciplina":"Literatura","tema":"Barroco Brasileiro","subtema":"Gregório de Matos","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Gregório de Matos Guerra é considerado o primeiro grande poeta brasileiro. Quais são as características do Barroco em sua obra?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Gregório de Matos (séc. XVII, Bahia): 'Boca do Inferno'. Características barrocas: (1) Dualismo/antítese — conflito entre sagrado e profano, carne e espírito; (2) Cultismo — jogo de palavras, latinismos, vocabulário rebuscado; (3) Conceptismo — raciocínio engenhoso, paradoxos; (4) Pessimismo e efemeridade (fugacidade do tempo — 'carpe diem'). Sua obra divide-se em: religiosa (lirismo espiritual), satírica/erótica (crítica feroz à sociedade colonial baiana) e lírico-amorosa. A sátira anticlerical e aos costumes da Bahia lhe valeu o exílio.","resposta":"Barroco: dualismo carne/espírito, cultismo, conceptismo, efemeridade. Obra satírica, religiosa e lírica — 'Boca do Inferno' crítico da Bahia colonial."},
{"id":"4311","tipo":"dissertativa","disciplina":"Matemática","tema":"Cálculo","subtema":"Integral definida — área","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"Calcule a área sob a curva f(x) = x² entre x=0 e x=3 usando integral definida.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"∫₀³ x² dx = [x³/3]₀³ = (3³/3) - (0³/3) = 27/3 - 0 = 9. A área sob a parábola f(x)=x² entre x=0 e x=3 é 9 unidades quadradas. Geometricamente: é a área delimitada pela parábola, o eixo x e a reta vertical x=3.","resposta":"Área = 9 unidades quadradas — ∫₀³ x²dx = 9"},
{"id":"4312","tipo":"dissertativa","disciplina":"Física","tema":"Eletricidade","subtema":"Campo elétrico","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O que é campo elétrico? Calcule o campo elétrico a 0,3 m de uma carga de 3×10⁻⁶ C. (k=9×10⁹ N·m²/C²)","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Campo elétrico E: força por unidade de carga que uma carga de prova positiva experienciaria naquele ponto. E = kQ/r². E = (9×10⁹ × 3×10⁻⁶) / (0,3)² = (27×10³) / 0,09 = 3×10⁵ N/C = 300.000 N/C. Direção: radial, afastando-se da carga (positiva).","resposta":"E = 3×10⁵ N/C (300.000 N/C), radial apontando para fora da carga"},
{"id":"4313","tipo":"dissertativa","disciplina":"Química","tema":"Bioquímica","subtema":"Ácidos nucleicos — DNA e RNA","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Compare DNA e RNA quanto à estrutura, composição e função.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"DNA: dupla hélice, desoxirribose, bases A-T-G-C, localizado no núcleo (e mitocôndrias/cloroplastos), função: armazenar e transmitir informação genética. RNA: fita simples (geralmente), ribose, bases A-U-G-C (uracila no lugar de timina). Tipos: mRNA (mensageiro — leva informação do DNA ao ribossomo), tRNA (transportador — carrega aminoácidos), rRNA (ribossomal — estrutura dos ribossomos). Fluxo da informação genética: DNA → RNA (transcrição) → Proteína (tradução) — Dogma Central da Biologia Molecular.","resposta":"DNA: dupla hélice, desoxirribose, armazena informação. RNA: fita simples, ribose + uracila, mensageiro/transportador/ribossomal."},
{"id":"4314","tipo":"dissertativa","disciplina":"Biologia","tema":"Ecologia","subtema":"Poluição e impactos ambientais","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O que é eutrofização? Explique o processo e suas consequências para os ecossistemas aquáticos.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Eutrofização: enriquecimento excessivo de nutrientes (N, P — de esgotos, fertilizantes agrícolas) em corpos d'água. Processo: aumento de nutrientes → proliferação explosiva de algas e cianobactérias (floração/bloom) → morte das algas → decomposição por bactérias aeróbias → consumo do O₂ dissolvido (hipóxia/anóxia) → morte de peixes e outros organismos aeróbios. Consequências: perda de biodiversidade aquática, mortandade de peixes, água inutilizável para consumo (toxinas de cianobactérias), odor e aspecto ruim. Ex.: Lago Paranoá (DF) sofreu eutrofização antes de ser tratado.","resposta":"Excesso de nutrientes → algas → decomposição → falta de O₂ → morte de peixes. Causa: esgoto e fertilizantes."},
{"id":"4315","tipo":"dissertativa","disciplina":"História","tema":"História Geral","subtema":"Queda do Muro de Berlim","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"A queda do Muro de Berlim (1989) é símbolo do fim da Guerra Fria. O que levou ao colapso do bloco soviético?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"O colapso soviético foi multifatorial: (1) Estagnação econômica (o sistema planificado não acompanhava o capitalismo); (2) Guerra do Afeganistão (1979-89) — sangria econômica e moral; (3) Perestroika (reestruturação econômica) e Glasnost (abertura política) de Gorbachev — criaram expectativas que não podiam ser controladas; (4) Movimentos nacionais nos países satélites (Solidariedade na Polônia, Primavera de Praga) que Gorbachev não reprimiu; (5) Corrida armamentista com os EUA (Reagan) esgotando a economia. Muro caiu em 09/11/1989 → reunificação alemã (1990) → dissolução da URSS (1991).","resposta":"Colapso soviético: estagnação econômica, Afeganistão, Glasnost/Perestroika, movimentos nacionais. Muro caiu 09/11/1989 → fim da URSS em 1991."},
{"id":"4316","tipo":"dissertativa","disciplina":"Geografia","tema":"Industrialização","subtema":"Desindustrialização brasileira","dificuldade":"Difícil","fonte":"Vestibular","ano":"2023","enunciado":"O Brasil passou por um processo de desindustrialização nas últimas décadas. Explique esse fenômeno e suas causas.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Desindustrialização: queda da participação da indústria no PIB e no emprego. No Brasil, a indústria representava ~35% do PIB nos anos 1980 e caiu para ~11-12% nos anos 2020. Causas: (1) Abertura econômica dos anos 1990 sem política industrial adequada — concorrência de importados; (2) Câmbio valorizado (desindustrialização relacionada ao boom das commodities — 'doença holandesa'); (3) Custo Brasil (infraestrutura, burocracia, carga tributária elevada); (4) Desvantagem frente à China e economias asiáticas de baixo custo; (5) Falta de investimento em P&D e inovação. Resultado: reprimarização da pauta exportadora (commodities agrícolas e minerais).","resposta":"Queda da indústria no PIB por abertura econômica, câmbio valorizado, custo Brasil e concorrência asiática. Resultado: reprimarização das exportações."},
{"id":"4317","tipo":"dissertativa","disciplina":"Português","tema":"Coesão e Coerência","subtema":"Conectivos e operadores argumentativos","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Explique a diferença entre coesão e coerência textuais. Dê exemplos de operadores argumentativos de adição, oposição e conclusão.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Coesão: mecanismos linguísticos de ligação entre as partes do texto (referência, substituição, ellipse, conjunções, léxico). Coerência: lógica semântica global — o texto faz sentido. Um texto pode ser coeso e incoerente (frases bem ligadas mas sem sentido) ou coerente sem coesão perfeita (textos coloquiais). Operadores argumentativos: Adição (e, além disso, também, ademais, outrossim). Oposição (mas, porém, contudo, todavia, entretanto, no entanto). Conclusão (portanto, logo, assim, por conseguinte, consequentemente). Cada um orienta o leitor sobre a relação lógica entre os argumentos.","resposta":"Coesão: links linguísticos. Coerência: sentido global. Adição: além disso. Oposição: contudo. Conclusão: portanto."},
{"id":"4318","tipo":"dissertativa","disciplina":"Filosofia","tema":"Estética","subtema":"Arte e beleza — Kant","dificuldade":"Difícil","fonte":"Vestibular","ano":"2023","enunciado":"Como Kant distingue o juízo de gosto (belo) do agradável e do bom? Por que o belo é 'universal sem conceito'?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Kant (Crítica do Juízo, 1790): Agradável: prazer sensorial subjetivo ('este vinho é bom') — sem pretensão universal. Bom: aprovação racional, moral — universal por conceito. Belo: satisfação desinteressada (não visa utilidade nem posse) + pretensão de acordo universal (esperamos que todos concordem) + sem submissão a conceito determinado + finalidade sem fim (parece ter propósito mas sem propósito definido). O belo é 'universal sem conceito' porque o juízo estético não se fundamenta num conceito lógico, mas numa 'comunicabilidade do sentimento' — esperamos que o sentimento de beleza seja compartilhável, embora não possamos prová-lo.","resposta":"Belo: desinteressado, universalidade subjetiva, sem conceito determinado. Diferente do agradável (subjetivo) e do bom (objetivo/moral)."},
{"id":"4319","tipo":"dissertativa","disciplina":"Sociologia","tema":"Poder e Dominação","subtema":"Foucault — biopoder","dificuldade":"Difícil","fonte":"Vestibular","ano":"2024","enunciado":"O que Michel Foucault entende por 'biopoder' e como ele se manifesta nas sociedades modernas?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Foucault: biopoder = conjunto de tecnologias de poder que tomam a vida biológica como objeto de controle. Duas formas: (1) Anátomo-política do corpo individual (disciplina) — controle dos corpos via hospitais, prisões, escolas, quartel; (2) Biopolítica da população — controle das populações via saúde pública, sexualidade, natalidade, imigração, eugenia. O biopoder administra a vida ('fazer viver e deixar morrer') — diferente do poder soberano ('fazer morrer e deixar viver'). Manifestações contemporâneas: controle de pandemias, biometria, regulação da reprodução, política de drogas, encarceramento em massa.","resposta":"Biopoder: controle político da vida biológica — disciplina dos corpos (individual) e biopolítica das populações. Manifestações: saúde pública, encarceramento, natalidade."},
{"id":"4320","tipo":"dissertativa","disciplina":"Literatura","tema":"Literatura Africana de Língua Portuguesa","subtema":"Mia Couto","dificuldade":"Difícil","fonte":"Vestibular","ano":"2023","enunciado":"Quais são as características da escrita de Mia Couto e como sua obra dialoga com a identidade moçambicana?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Mia Couto (Moçambique, n. 1955): linguagem inventiva com neologismos e recriações do português africano ('a língua é uma pátria que carregamos'). Características: neologismos ('desingano', 'invejonar'), fusão de oralidade africana com escrita literária, realismo mágico, elementos de espiritualidade bantu. Obras: 'Terra Sonâmbula', 'O Último Voo do Flamingo', 'Antes de Nascer o Mundo'. Diálogo com Moçambique: processa o trauma da guerra civil pós-independência, a identidade híbrida entre tradição africana e herança colonial portuguesa, a reconstrução nacional. A língua portuguesa reinventada torna-se veículo de expressão da alma moçambicana.","resposta":"Neologismos, oralidade africana, realismo mágico, língua reinventada. Processa a guerra civil e identidade híbrida moçambicana."},
{"id":"4321","tipo":"dissertativa","disciplina":"Matemática","tema":"Trigonometria","subtema":"Funções trigonométricas no círculo trigonométrico","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Sem usar calculadora, determine sen(120°), cos(120°) e tg(120°).","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"120° está no 2° quadrante. Ângulo de referência: 180°-120°=60°. sen(120°) = sen(60°) = √3/2 (positivo no 2°Q). cos(120°) = -cos(60°) = -1/2 (negativo no 2°Q). tg(120°) = sen/cos = (√3/2)/(-1/2) = -√3 (negativo no 2°Q).","resposta":"sen(120°) = √3/2; cos(120°) = -1/2; tg(120°) = -√3"},
{"id":"4322","tipo":"dissertativa","disciplina":"Física","tema":"Termodinâmica","subtema":"Máquinas térmicas — eficiência","dificuldade":"Difícil","fonte":"Vestibular","ano":"2023","enunciado":"Uma máquina térmica opera entre reservatórios a 400 K e 300 K. Qual a eficiência máxima (Carnot) e quantos Joules de trabalho ela realiza se absorver 8000 J?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Eficiência de Carnot: η = 1 - T_fria/T_quente = 1 - 300/400 = 1 - 0,75 = 0,25 = 25%. Trabalho: W = η × Q_absorvido = 0,25 × 8000 = 2000 J. Calor rejeitado: Q_fria = Q_quente - W = 8000 - 2000 = 6000 J. Nenhuma máquina real pode superar essa eficiência para essas temperaturas (2ª Lei).","resposta":"η_Carnot = 25%; W = 2000 J; Q rejeitado = 6000 J"},
{"id":"4323","tipo":"dissertativa","disciplina":"Química","tema":"Orgânica","subtema":"Reações de saponificação","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que é saponificação? Escreva a reação geral e explique por que o sabão remove gordura.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Saponificação: hidrólise alcalina de ésteres (triglicerídeos/gorduras) com NaOH ou KOH. Reação: triglicerídeo + 3NaOH → glicerol + 3 sais de ácidos graxos (sabão). Ex.: gordura de coco + NaOH → glicerina + sabão. O sabão remove gordura porque possui estrutura anfipática: cauda apolar (cadeia carbônica longa — hidrofóbica, interage com a gordura) e cabeça polar (carboxilato — hidrofílica, interage com a água). Forma micelas que encapsulam a gordura e são arrastadas pela água.","resposta":"Saponificação: gordura + NaOH → sabão + glicerol. Sabão é anfipático: cauda hidrofóbica encapsula gordura, cabeça hidrofílica solubiliza em água."},
{"id":"4324","tipo":"dissertativa","disciplina":"Biologia","tema":"Saúde","subtema":"Sistema imune — vacinas","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Explique o mecanismo de ação das vacinas. Por que algumas vacinas precisam de doses de reforço?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Vacinas: introduzem antígenos (vírus atenuado, morto, proteína ou mRNA) no organismo sem causar doença. O sistema imune monta resposta primária: ativa linfócitos B (anticorpos) e T citotóxicos → formação de células de memória. Em exposição futura ao patógeno real: resposta secundária muito mais rápida e intensa (células de memória). Tipos: atenuada (sarampo, febre amarela), inativada (influenza), subunidade proteica (hepatite B), mRNA (COVID-19). Reforços: alguns antígenos geram memória de curta duração (influenza muta, exigindo vacina anual) ou a imunidade diminui ao longo do tempo (tétano a cada 10 anos).","resposta":"Vacinas ativam sistema imune sem doença, criando memória. Reforços necessários quando a memória é de curta duração ou o patógeno muta (influenza, COVID)."},
{"id":"4325","tipo":"dissertativa","disciplina":"História","tema":"História Geral","subtema":"Neoliberalismo","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que é neoliberalismo? Quando surgiu e quais foram seus principais impactos nas políticas econômicas globais?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Neoliberalismo: doutrina econômica que prega livre mercado, Estado mínimo, privatizações, desregulamentação, corte de gastos sociais e abertura comercial. Origens teóricas: Hayek, Friedman, Escola de Chicago. Implementação: Chile de Pinochet (1973, com 'Chicago Boys'), Thatcher (Reino Unido, 1979) e Reagan (EUA, 1981). Consenso de Washington (1989): receituário do FMI/Banco Mundial para países em desenvolvimento (privatizações, ajuste fiscal, liberalização). Impactos: crescimento econômico em alguns casos, mas aumento da desigualdade, precarização do trabalho, crises financeiras (México 1994, Ásia 1997, Argentina 2001), enfraquecimento de sindicatos e Estado de bem-estar social.","resposta":"Estado mínimo, livre mercado, privatizações. Thatcher/Reagan nos 80s. Consenso de Washington → privatizações no Sul Global. Impacto: desigualdade crescente."},
{"id":"4326","tipo":"dissertativa","disciplina":"Geografia","tema":"Urbanização","subtema":"Favelas e habitação","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Como se formaram as favelas no Brasil e quais são os principais desafios para a política habitacional?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Origem: migração rural-urbana acelerada (séc. XX) sem política habitacional adequada + especulação imobiliária que expulsou pobres das áreas centrais. A primeira favela reconhecida: Morro da Providência (Rio, 1897 — ex-combatentes de Canudos). Crescimento: êxodo rural dos anos 1950-80 superlotou cidades sem infraestrutura. Desafios habitacionais: (1) Déficit habitacional (~8 milhões de unidades no Brasil); (2) Regularização fundiária (segurança de posse); (3) Urbanização de favelas com infraestrutura (saneamento, pavimentação); (4) Programas como 'Minha Casa, Minha Vida' têm alcance limitado; (5) Especulação imobiliária; (6) Violência e tráfico dificultam intervenção pública.","resposta":"Origem: migração sem política habitacional. Desafios: déficit de 8 mi de unidades, regularização fundiária, saneamento, especulação imobiliária."},
{"id":"4327","tipo":"dissertativa","disciplina":"Português","tema":"Literatura","subtema":"Modernismo — Oswald de Andrade","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que foi o 'Manifesto Antropófago' de Oswald de Andrade (1928) e qual sua importância para a cultura brasileira?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Manifesto Antropófago (1928): proposta de Oswald de Andrade de 'devorar' criativamente as influências estrangeiras, transformando-as em algo novo e brasileiro — como os tupinambás devoravam inimigos para absorver suas qualidades. 'Só me interessa o que não é meu.' Metáfora da deglutição cultural: absorver o melhor da cultura europeia/universal e regurgitá-la como arte brasileira original. Importância: fundou uma visão de identidade cultural brasileira não submissa à Europa, influenciou o Tropicalismo (anos 60-70), a MPB, as artes plásticas e o pensamento cultural brasileiro contemporâneo. Frase célebre: 'Tupi or not Tupi, that is the question.'","resposta":"Devorar culturas estrangeiras e transformá-las em arte brasileira original. Base do Tropicalismo e da identidade cultural não-submissa à Europa."},
{"id":"4328","tipo":"dissertativa","disciplina":"Filosofia","tema":"Filosofia da Mente","subtema":"Dualismo e monismo","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Explique o dualismo cartesiano mente-corpo e as principais objeções a essa teoria.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Descartes: duas substâncias distintas — res cogitans (mente/pensamento, imaterial, indivisível) e res extensa (corpo/matéria, divisível, ocupa espaço). A mente não é redutível ao corpo. Problema: como substâncias tão distintas interagem? (glândula pineal proposta como ponto de contato). Objeções: (1) Interação causal: como imaterial afeta material? (2) Epifenomenismo: talvez a mente seja apenas 'subproduto' do cérebro sem causal power; (3) Fisicalismo/materialismo: a mente É atividade cerebral — neurociência reduz estados mentais a estados físicos; (4) Problema de Princess Elisabeth: como a mente move o corpo sem ocupar espaço? O dualismo permanece controverso apesar da dominância do fisicalismo atual.","resposta":"Descartes: mente (imaterial) e corpo (material) são substâncias distintas. Problema: como interagem? Fisicalismo moderno reduz mente ao cérebro."},
{"id":"4329","tipo":"dissertativa","disciplina":"Sociologia","tema":"Trabalho","subtema":"Precarização do trabalho","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que é a 'uberização do trabalho'? Como esse fenômeno afeta os direitos trabalhistas no Brasil?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Uberização: modelo de trabalho baseado em plataformas digitais que classificam trabalhadores como 'autônomos' ou 'parceiros' — transferindo riscos para o indivíduo e eliminando vínculos empregatícios formais. Características: trabalho sob demanda, controle algorítmico, sem férias/FGTS/INSS pelo empregador, ilusão de autonomia. No Brasil: ~1,5 milhão de motoristas de aplicativo (2023), milhões de entregadores. Impactos: eliminação de direitos trabalhistas (CLT), precarização da renda (variável e insuficiente), acidentalidade sem cobertura, dificuldade de organização sindical. Debate jurídico: STF discute vínculo empregatício de entregadores — tensão entre inovação tecnológica e proteção social.","resposta":"Plataformas classificam trabalhadores como autônomos para não garantir direitos CLT. Impactos: sem férias, FGTS, acidente de trabalho — precarização estrutural."},
{"id":"4330","tipo":"dissertativa","disciplina":"Literatura","tema":"Arcadismo Brasileiro","subtema":"Tomás Antônio Gonzaga","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Quais são as características do Arcadismo e como se manifestam em 'Marília de Dirceu' de Tomás Antônio Gonzaga?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Arcadismo (2ª metade séc. XVIII): reação ao Barroco — valoriza a simplicidade, a razão, a natureza pastoral. Características: 'Inutilia truncat' (cortar o inútil), 'Aurea mediocritas' (mediocridade áurea — equilíbrio), 'Fugere urbem' (fugir da cidade), 'Carpe diem' (aproveitar o momento), uso de pseudônimos pastoris. 'Marília de Dirceu' (Gonzaga): poemas lírico-amorosos dedicados a Maria Doroteia (Marília). Reflete o Arcadismo: linguagem simples, cenários bucólicos, exaltação do amor sereno e da vida no campo. A história real (amor de Gonzaga e a Inconfidência Mineira) adiciona dramaticidade — ele foi preso e exilado.","resposta":"Arcadismo: simplicidade, natureza, razão. 'Marília de Dirceu': amor bucólico, linguagem simples, pseudônimos pastoris — Gonzaga preso pela Inconfidência."},
{"id":"4331","tipo":"dissertativa","disciplina":"Matemática","tema":"Geometria Analítica","subtema":"Equação da reta","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Determine a equação da reta que passa pelos pontos A(1,2) e B(3,8).","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Coeficiente angular: m = (y₂-y₁)/(x₂-x₁) = (8-2)/(3-1) = 6/2 = 3. Equação: y - y₁ = m(x - x₁) → y - 2 = 3(x - 1) → y = 3x - 3 + 2 → y = 3x - 1. Verificação: B(3,8): 3×3-1=8 ✓","resposta":"y = 3x - 1"},
{"id":"4332","tipo":"dissertativa","disciplina":"Física","tema":"Ondas","subtema":"Equação fundamental da ondulatória","dificuldade":"Fácil","fonte":"Vestibular","ano":"2023","enunciado":"Uma onda tem frequência de 440 Hz (nota Lá) e velocidade de propagação de 340 m/s no ar. Calcule seu comprimento de onda.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"v = λ×f → λ = v/f = 340/440 ≈ 0,773 m ≈ 77,3 cm. A nota Lá (440 Hz) tem comprimento de onda de aproximadamente 77 cm no ar a temperatura ambiente.","resposta":"λ ≈ 0,773 m (77,3 cm)"},
{"id":"4333","tipo":"dissertativa","disciplina":"Química","tema":"Orgânica","subtema":"Polímeros naturais — borracha","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Explique o processo de vulcanização da borracha natural e como ele melhora suas propriedades.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Borracha natural: poliisopreno (C₅H₈)ₙ extraído da seringueira (Hevea brasiliensis). Problema: pegajosa no calor, quebradiça no frio, deforma facilmente. Vulcanização (Goodyear, 1839): aquecimento com enxofre forma pontes de enxofre (ligações cruzadas -S-S-) entre as cadeias poliméricas. Resultado: borracha mais elástica, resistente ao calor e ao frio, menos pegajosa, mais durável. Aplicações: pneus, solas de sapato, luvas cirúrgicas. A vulcanização transformou a borracha em material industrial viável — contribuindo para o 'Ciclo da Borracha' na Amazônia.","resposta":"Vulcanização: enxofre cria pontes entre cadeias → borracha mais elástica, resistente e durável. Base dos pneus e da indústria automobilística."},
{"id":"4334","tipo":"dissertativa","disciplina":"Biologia","tema":"Genética","subtema":"Mutações gênicas","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O que são mutações gênicas? Quais são os tipos principais e quando podem ser benéficas?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Mutações gênicas: alterações na sequência de bases nitrogenadas do DNA. Tipos: (1) Substituição (missense — troca de aminoácido; nonsense — gera stop codon; silenciosa — sem mudança de aa); (2) Inserção — adiciona bases; (3) Deleção — remove bases; inserção/deleção causam frameshift (deslocamento de leitura) se não múltiplos de 3. Causas: erros de replicação, radiação, mutágenos químicos, vírus. Maioria é neutra ou deletéria; raramente benéfica. Mutações benéficas: resistência a HIV em indivíduos com mutação CCR5Δ32; resistência à malária em portadores de célula falciforme heterozigóticos; são matéria-prima da evolução.","resposta":"Mutações: substituição, inserção, deleção. Maioria neutra/deletéria. Raramente benéficas (CCR5Δ32 x HIV, resistência à malária) — matéria-prima da evolução."},
{"id":"4335","tipo":"dissertativa","disciplina":"História","tema":"História do Brasil","subtema":"Redemocratização — Diretas Já","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O movimento 'Diretas Já' (1983-84) foi um marco da redemocratização brasileira. Descreva-o e explique seu resultado.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Diretas Já: movimento popular que exigia eleições diretas para presidente — reprimidas desde 1964. Mobilizou milhões em comícios por todo o Brasil (São Paulo, Rio, Belo Horizonte). A Emenda Dante de Oliveira (propunha eleições diretas) foi derrotada no Congresso em abril de 1984. Resultado paradoxal: eleição indireta pelo Colégio Eleitoral — Tancredo Neves venceu Maluf (candidato do regime). Tancredo morreu antes de tomar posse; José Sarney assumiu como primeiro presidente civil desde 1964. As Diretas Já, apesar de 'derrotadas', aceleraram o fim da Ditadura e levaram ao processo constitucional de 1987-88.","resposta":"Mobilização por eleições diretas (1984). Emenda derrotada no Congresso. Tancredo venceu no Colégio Eleitoral mas morreu; Sarney assumiu — transição democrática."},
{"id":"4336","tipo":"dissertativa","disciplina":"Geografia","tema":"Globalização","subtema":"Fluxos migratórios contemporâneos","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Quais são as principais causas dos fluxos migratórios internacionais contemporâneos e como o Brasil se insere nesse contexto?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Causas dos fluxos migratórios: (1) Econômicas — busca por trabalho e melhores condições (migração voluntária); (2) Políticas — fuga de conflitos armados, perseguições, ditaduras (refugiados — Convenção de Genebra 1951); (3) Ambientais — desastres, mudanças climáticas (refugiados climáticos — novo fenômeno); (4) Familiares — reunificação. Brasil no contexto: receptor de haitianos (pós-terremoto 2010), venezuelanos (crise política/econômica — maior fluxo da história brasileira), sírios. Também emissor: brasileiros no exterior (EUA, Portugal, Japão). Lei de Migração (2017) substituiu o Estatuto do Estrangeiro ditatorial, garantindo direitos aos migrantes.","resposta":"Causas: econômicas, políticas (refugiados), ambientais. Brasil: receptor de haitianos e venezuelanos; emissor para EUA, Portugal, Japão."},
{"id":"4337","tipo":"dissertativa","disciplina":"Português","tema":"Literatura","subtema":"Cruz e Sousa — Simbolismo","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Cruz e Sousa é o maior representante do Simbolismo no Brasil. Quais são as características simbólicas de sua obra e como sua identidade racial influencia sua poesia?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Cruz e Sousa (1861-1898, SC): filho de ex-escravizados, sofreu discriminação racial apesar do talento reconhecido. Obra: 'Broquéis', 'Missal', 'Evocações'. Características simbolistas: musicalidade intensa (aliteração, assonância), sinestesia, sugestão em vez de descrição, linguagem hermética/obscura, temas: morte, espiritualidade, transcendência, ideal inalcançável. Identidade racial: a cor negra aparece sublimada ou transfigurada em branco ('Acrobata da Dor', 'Emparedado' — a cor é metáfora do isolamento e da opressão sofrida). O sofrimento racial transforma-se em angústia existencial universal — traço único que diferencia sua poesia dos simbolistas europeus.","resposta":"Simbolismo: musicalidade, sinestesia, hermetismo, transcendência. Identidade negra: cor sublimada como metáfora da opressão existencial ('Emparedado')."},
{"id":"4338","tipo":"dissertativa","disciplina":"Filosofia","tema":"Filosofia da História","subtema":"Hegel — dialética histórica","dificuldade":"Difícil","fonte":"Vestibular","ano":"2023","enunciado":"Explique a dialética hegeliana (tese, antítese, síntese) aplicada à filosofia da história.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Hegel: a realidade e a história se desenvolvem dialeticamente. Dialética: (1) Tese — uma posição/momento histórico; (2) Antítese — a negação/contradição da tese; (3) Síntese (Aufhebung = superação) — supera e conserva elementos da tese e antítese num nível superior. A história é a auto-realização do Espírito (Geist) através de conflitos. Exemplos: Mundo Antigo (tese) → crítica socrática/cristã (antítese) → Idade Média (síntese parcial) → etc. Marx inverteu Hegel: a dialética não é do Espírito, mas da matéria/relações de produção (materialismo histórico-dialético). Hegel: 'A história universal é o tribunal do mundo.'","resposta":"Tese → antítese → síntese (Aufhebung): superação que conserva. História = auto-realização do Espírito. Marx inverte para materialismo dialético."},
{"id":"4339","tipo":"dissertativa","disciplina":"Sociologia","tema":"Raça e Etnia","subtema":"Racismo estrutural","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que é racismo estrutural segundo Silvio Almeida? Como ele difere do racismo individual?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Silvio Almeida ('Racismo Estrutural', 2018): racismo não é apenas atitude individual (preconceito consciente), mas está enraizado nas instituições e estruturas da sociedade. Individual: atos deliberados de preconceito ou discriminação. Institucional: quando organizações (polícia, judiciário, empresas) reproduzem desigualdades raciais sistematicamente, mesmo sem intenção explícita. Estrutural: o racismo é o modo normal de funcionamento da sociedade — reproduzido por processos econômicos, políticos e jurídicos. Evidências: encarceramento (64% dos presos no Brasil são negros), mercado de trabalho, saúde (maior mortalidade materna negra), acesso à educação. O conceito desloca o foco do indivíduo racista para o sistema que o produz.","resposta":"Racismo estrutural: modo normal de funcionamento social que reproduz desigualdades raciais sistematicamente — além do preconceito individual ou institucional isolado."},
{"id":"4340","tipo":"dissertativa","disciplina":"Literatura","tema":"Literatura Contemporânea","subtema":"Chico Buarque — prosa","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Em 'Budapeste' de Chico Buarque, o protagonista José Costa é um ghostwriter. Como o romance explora a questão da identidade e da autoria?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"'Budapeste' (2003): José Costa escreve para outros sem assinar. Em Budapeste, aprende húngaro e se vê diante do paradoxo: sua obra mais pessoal (escrita em húngaro) não pode ser sua autoria reconhecida. O romance explora: (1) Identidade fragmentada — quem é o autor se o nome não é seu? (2) A linguagem como constituição do sujeito — ao aprender húngaro, Costa se transforma; (3) O duplo: José Costa em São Paulo vs. Zsoze Kosta em Budapeste; (4) Metaficção: um livro sobre escritores que não assinam livros. Tema central: é possível existir sem nome? A autoria é condição da identidade?","resposta":"Ghostwriter sem identidade autoral: o romance questiona se existimos sem nome próprio. Identidade fragmentada entre SP e Budapeste, linguagem como transformação do sujeito."},
{"id":"4341","tipo":"dissertativa","disciplina":"Matemática","tema":"Combinatória","subtema":"Combinações","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"De quantas maneiras podemos escolher 3 pessoas de um grupo de 10 para formar uma comissão?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Combinação: C(10,3) = 10!/(3!×7!) = (10×9×8)/(3×2×1) = 720/6 = 120. Usamos combinação (não arranjo) porque a ordem dos escolhidos não importa — a comissão {A,B,C} é igual a {C,A,B}.","resposta":"C(10,3) = 120 maneiras"},
{"id":"4342","tipo":"dissertativa","disciplina":"Física","tema":"Eletromagnetismo","subtema":"Lei de Ampère","dificuldade":"Difícil","fonte":"Vestibular","ano":"2023","enunciado":"Enuncie a Lei de Ampère e explique como ela relaciona corrente elétrica e campo magnético.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Lei de Ampère: ∮B·dl = μ₀I — a integral de linha do campo magnético B ao longo de um caminho fechado é proporcional à corrente total I que atravessa a superfície delimitada por esse caminho. μ₀ = 4π×10⁻⁷ T·m/A (permeabilidade do vácuo). Em termos práticos: um fio retilíneo com corrente I cria um campo magnético circular ao seu redor — B = μ₀I/(2πr). Aplicações: solenoides (B = μ₀nI), toroides, eletroímãs. Maxwell generalizou com a corrente de deslocamento → Equações de Maxwell → Ondas eletromagnéticas.","resposta":"Lei de Ampère: corrente gera campo magnético circular. B = μ₀I/(2πr) para fio reto. Base dos solenoides e eletroímãs."},
{"id":"4343","tipo":"dissertativa","disciplina":"Química","tema":"Analytical","subtema":"Titulação ácido-base","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Em uma titulação, 25 mL de HCl consomem 20 mL de NaOH 0,5 mol/L para atingir o ponto de equivalência. Calcule a concentração do HCl.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"No ponto de equivalência: n(HCl) = n(NaOH) (relação 1:1). n(NaOH) = C×V = 0,5 × 0,020 L = 0,010 mol. n(HCl) = 0,010 mol. C(HCl) = n/V = 0,010/0,025 = 0,4 mol/L.","resposta":"[HCl] = 0,4 mol/L"},
{"id":"4344","tipo":"dissertativa","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Sistema endócrino","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Compare a regulação nervosa e a regulação hormonal do organismo humano quanto à velocidade, duração e especificidade.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Regulação nervosa: rápida (milissegundos — impulso elétrico), efeito de curta duração, altamente localizada e específica (neurônio → órgão específico). Regulação hormonal (endócrina): lenta (segundos a horas — hormônio percorre a corrente sanguínea), efeito prolongado (horas a dias), age em órgãos-alvo com receptores específicos (mas difusamente via sangue). Exemplos: reflexo de retirada (nervoso — imediato), crescimento puberal (hormonal — gradual). Os dois sistemas se integram: hipotálamo/hipófise coordenam ambos; adrenalina é hormônio E neurotransmissor.","resposta":"Nervosa: rápida, curta, localizada. Hormonal: lenta, prolongada, via sangue. Integradas pelo eixo hipotálamo-hipófise."},
{"id":"4345","tipo":"dissertativa","disciplina":"História","tema":"História Geral","subtema":"Imperialismo norte-americano","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que foi a 'Doutrina Monroe' e como ela embasou a política externa dos EUA na América Latina?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Doutrina Monroe (1823, Presidente James Monroe): 'A América para os americanos' — oposição a novas colonizações europeias no continente americano; qualquer intervenção europeia seria vista como ameaça aos EUA. Inicialmente defensiva, foi reinterpretada pelo Corolário Roosevelt (1904): os EUA se reservam o direito de intervir em países latino-americanos que não 'mantenham ordem'. Na prática: justificou intervenções militares no México, Nicarágua, Haiti, Cuba, República Dominicana, Panamá. Durante a Guerra Fria: usada para justificar apoio a ditaduras anticomunistas na AL (Chile, Argentina, Brasil 1964). Legado: imperialismo velado com discurso de defesa hemisférica.","resposta":"Monroe (1823): 'América para americanos' — veto à colonização europeia. Corolário Roosevelt: EUA podem intervir na AL. Justificou imperialismo e apoio a ditaduras na Guerra Fria."},
{"id":"4346","tipo":"dissertativa","disciplina":"Geografia","tema":"Questão Indígena","subtema":"Povos indígenas no Brasil contemporâneo","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Qual é a situação atual dos povos indígenas no Brasil? Quais são as principais ameaças aos seus territórios e direitos?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Situação: ~1,7 milhão de indígenas (IBGE 2022), ~305 povos, ~274 línguas. Terras Indígenas demarcadas: ~690 (14% do território nacional). Ameaças: (1) Invasão de garimpo ilegal (ouro, cassiterita) — impactos ambientais e de saúde (caso Yanomami, 2023); (2) Desmatamento e agronegócio pressionando TIs; (3) Marco temporal (tese jurídica que limitaria demarcações); (4) Violência contra lideranças indígenas; (5) Evangelização e aculturação forçada. Constituição de 1988 (Art. 231): garante direitos originários às terras que habitam. FUNAI e SESAI são responsáveis pela proteção — subfinanciadas. Lideranças como Sônia Guajajara e Ailton Krenak têm protagonismo crescente.","resposta":"1,7 mi de indígenas, 305 povos, 690 TIs. Ameaças: garimpo ilegal, agronegócio, marco temporal, violência. CF/88 garante direitos territoriais originários."},
{"id":"4347","tipo":"dissertativa","disciplina":"Português","tema":"Gramática","subtema":"Crase","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"Explique as regras de uso da crase. Dê exemplos de quando é obrigatória, facultativa e proibida.","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Crase: fusão de preposição 'a' com artigo 'a' ou pronomes 'aquele(a)'. Obrigatória: antes de palavras femininas com artigo definido ('Fui à escola', 'Refiro-me à professora'); locuções adverbiais femininas ('à tarde', 'às pressas'); antes de 'aquela(s)', 'aquele(s)', 'aquilo' ('Refiro-me àquele problema'). Facultativa: antes de pronomes possessivos femininos ('Fui a/à sua casa'); nomes de lugares que aceitam artigo ('Fui a/à Lisboa'). Proibida: antes de palavras masculinas ('Fui a pé'); antes de verbos ('Começou a chover'); antes de pronomes pessoais/demonstrativos ('Entreguei a ela'); expressões indicando horas de forma indeterminada ('Abriu a partir de que hora?').","resposta":"Obrigatória: à escola, à tarde. Facultativa: à/a sua casa. Proibida: antes de masculinos, verbos, pronomes pessoais."},
{"id":"4348","tipo":"dissertativa","disciplina":"Filosofia","tema":"Ética","subtema":"Bioética","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"Quais são os quatro princípios fundamentais da bioética (Beauchamp e Childress) e como se aplicam na prática médica?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Beauchamp e Childress ('Principles of Biomedical Ethics', 1979): (1) Autonomia: respeito à capacidade do paciente de tomar decisões informadas (consentimento livre e esclarecido, direito de recusar tratamento); (2) Beneficência: obrigação de agir em benefício do paciente (fazer o bem); (3) Não maleficência: evitar causar dano ('primum non nocere' — acima de tudo, não prejudicar); (4) Justiça: distribuição equitativa de benefícios, riscos e custos — acesso igualitário à saúde. Conflitos práticos: eutanásia (autonomia vs. não maleficência); transplantes (justiça distributiva); pesquisas com humanos (autonomia + beneficência coletiva). Os 4 princípios guiam comitês de ética e decisões clínicas complexas.","resposta":"Autonomia, beneficência, não maleficência, justiça. Guiam decisões clínicas e resolução de conflitos éticos na medicina."},
{"id":"4349","tipo":"dissertativa","disciplina":"Sociologia","tema":"Mídia e Comunicação","subtema":"Fake news e pós-verdade","dificuldade":"Médio","fonte":"Vestibular","ano":"2024","enunciado":"O que são 'fake news' e 'pós-verdade'? Como esses fenômenos afetam a democracia?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Fake news: desinformação deliberada — notícias falsas criadas com intenção de enganar, viralizar e manipular a opinião pública. Pós-verdade (Oxford Word of the Year 2016): contexto em que apelos emocionais e crenças pessoais influenciam mais a opinião pública do que fatos verificáveis. Fenômeno amplificado pelas redes sociais (algoritmos de bolhas, viralização de conteúdo emotivo). Impactos na democracia: (1) Erosão da confiança em instituições e imprensa; (2) Polarização política extrema; (3) Manipulação eleitoral (Cambridge Analytica); (4) Dificuldade de formação de consenso em democracias; (5) Negacionismo científico (vacinas, clima). Respostas: fact-checking, educação midiática, regulação de plataformas.","resposta":"Fake news: desinformação deliberada. Pós-verdade: emoção supera fatos. Impactos: erosão democrática, polarização, manipulação eleitoral."},
{"id":"4350","tipo":"dissertativa","disciplina":"Literatura","tema":"Literatura de Cordel","subtema":"Cordel nordestino","dificuldade":"Médio","fonte":"Vestibular","ano":"2023","enunciado":"O que é a literatura de cordel? Quais são suas características formais e qual sua importância cultural no Nordeste?","alternativa_a":"","alternativa_b":"","alternativa_c":"","alternativa_d":"","alternativa_e":"","resposta_correta":"","explicacao":"Cordel: manifestação literária popular do Nordeste brasileiro, vendida em folhetos pendurados em cordas. Características formais: versos rimados em sextilhas (6 versos, 2º-4º-6º rimam) ou décimas; linguagem acessível com humor, crítica social e fantasia; ilustração em xilogravura na capa. Temas: heróis populares (Lampião, Padre Cícero, Antônio Silvino), amor, morte, política, fatos cotidianos, religiosidade. Importância cultural: preserva a cultura oral nordestina; democratiza a literatura (barato, acessível); registra a história local; influenciou artistas como Ariano Suassuna. Reconhecido como Patrimônio Cultural Imaterial do Brasil (IPHAN, 2018).","resposta":"Folhetos rimados em sextilhas, xilogravura, temas populares (Lampião, política, amor). Patrimônio cultural imaterial nordestino, raiz da identidade regional."},
]

